#include <string>
#include <unordered_map>
#include <algorithm>
using namespace std;

int solve(int n, vector<vector<int>> edges, string label) {
    vector<vector<int>> adj(n);
    for (const auto& e : edges) {
        adj[e[0]].push_back(e[1]);
        adj[e[1]].push_back(e[0]);
    }

    int max_len = 1;

    for (int start = 0; start < n; ++start) {
        vector<vector<int>> dp(n, vector<int>(n, 0));
        // dp[u][v] represents the max palindrome length in the path u...v
        for (int u = 0; u < n; ++u) {
            dp[u][u] = 1;
        }

        for (int len = 2; len <= n; ++len) {
            for (int u = 0; u < n; ++u) {
                for (int v : adj[u]) {
                    if (dp[u][v] != 0) continue;
                    if (label[u] == label[v]) {
                        if (len == 2) {
                            dp[u][v] = 2;
                        } else {
                            for (int w : adj[v]) {
                                if (w == u) continue;
                                if (dp[u][w] == len - 2) {
                                    dp[u][v] = len;
                                    break;
                                }
                            }
                        }
                    } else {
                        for (int w : adj[v]) {
                            if (w == u) continue;
                            if (dp[u][w] == len - 1) {
                                dp[u][v] = len - 1;
                                break;
                            }
                        }
                    }
                    if (dp[u][v] > max_len) {
                        max_len = dp[u][v];
                    }
                }
            }
        }
    }

    return max_len;
}
