#include <unordered_map>
#include <algorithm>
using namespace std;

int max_len = 1;

void dfs(int node, unordered_map<int, vector<int>>& graph, string& label, vector<bool>& visited, unordered_map<char, int>& freq) {
    visited[node] = true;
    freq[label[node]]++;

    int odd_count = 0;
    int total = 0;
    for (auto& [ch, cnt] : freq) {
        if (cnt % 2 == 1) {
            odd_count++;
        }
        total += cnt;
    }

    if (odd_count <= 1) {
        max_len = max(max_len, total);
    }

    for (int neighbor : graph[node]) {
        if (!visited[neighbor]) {
            dfs(neighbor, graph, label, visited, freq);
        }
    }

    freq[label[node]]--;
    if (freq[label[node]] == 0) {
        freq.erase(label[node]);
    }
    visited[node] = false;
}

long long solve(long long n, vector<vector<long long>> edges, string label) {
