#include <vector>
#include <string>
#include <unordered_map>
#include <algorithm>
using namespace std;

int dfs(int node, int mask, const vector<vector<int>>& graph, const string& label, unordered_map<int, unordered_map<int, int>>& memo) {
    if (memo.count(node) && memo[node].count(mask)) {
        return memo[node][mask];
    }

    int max_len = 1;
    for (int neighbor : graph[node]) {
        if (!(mask & (1 << neighbor))) {
            int new_mask = mask | (1 << neighbor);
            int current_len = dfs(neighbor, new_mask, graph, label, memo);
            if (label[node] == label[neighbor]) {
                max_len = max(max_len, current_len + 2);
            } else {
                max_len = max(max_len, current_len);
            }
        }
    }

    memo[node][mask] = max_len;
    return max_len;
}

long long solve(long long n, vector<vector<long long>> edges, string label) {
    vector<vector<int>> graph(n);
    for (const auto& edge : edges) {
        int u = edge[0];
        int v = edge[1];
        graph[u].push_back(v);
        graph[v].push_back(u);
    }

    unordered_map<int, unordered_map<int, int>> memo;
    int max_palindrome = 1;
    for (int i = 0; i < n; ++i) {
        int mask = (1 << i);
        max_palindrome = max(max_palindrome, dfs(i, mask, graph, label, memo));
    }

    return max_palindrome;
}
